export default async function (request, context) {
  const xml = `<note><to>User</to><from>Admin</from><heading>Reminder</heading><body>Don't forget the meeting!</body></note>`;
  return new Response(xml, {
    headers: {
      "content-type": "application/xml",
    },
  });
}

import { XMLParser } from "fast-xml-parser";

export default async function (response, request, context) {
  const contentType = response.headers.get("content-type");
  if (contentType && contentType.includes("application/xml")) {
    const xmlText = await response.text();
    const parser = new XMLParser();
    const jsonObj = parser.parse(xmlText);

    return new Response(JSON.stringify(jsonObj), {
      status: response.status,
      statusText: response.statusText,
      headers: {
        ...Object.fromEntries(response.headers.entries()),
        "content-type": "application/json",
      },
    });
  }
  return response;
}
